 1	import React, { FC, memo } from 'react';
 2	import { FormProvider, useForm } from 'react-hook-form';
 3	
 4	import { DRAWER_FORM_ID } from '@catalog/templatescatalog/utils/consts';
 5	import HardwareDevices from '@kubevirt-utils/components/HardwareDevices/HardwareDevices';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { getGPUDevices, getHostDevices } from '@kubevirt-utils/resources/vm';
 8	import {
 9	  DescriptionListDescription,
10	  ExpandableSection,
11	  Form,
12	  Grid,
13	  GridItem,
14	  Stack,
15	  StackItem,
16	} from '@patternfly/react-core';
17	
18	import { useDrawerContext } from './hooks/useDrawerContext';
19	import StorageSection from './StorageSection/StorageSection';
20	import FieldsSections from './FieldsSections';
21	import { TemplateInfoSection } from './TemplateInfoSection';
22	
23	export const TemplatesCatalogDrawerPanel: FC = memo(() => {
24	  const { t } = useKubevirtTranslation();
25	
26	  const { vm } = useDrawerContext();
27	  const hostDevicesCount = getHostDevices(vm)?.length || 0;
28	  const gpusCount = getGPUDevices(vm)?.length || 0;
29	  const hardwareDevicesCount = hostDevicesCount + gpusCount;
30	
31	  const methods = useForm();
32	
33	  return (
34	    <div className="modal-body modal-body-border modal-body-content">
35	      <div className="modal-body-inner-shadow-covers">
36	        <div className="co-catalog-page__overlay-body">
37	          <FormProvider {...methods}>
38	            <Form id={DRAWER_FORM_ID}>
39	              <Grid hasGutter>
40	                <GridItem span={6}>
41	                  <Stack className="template-catalog-drawer-info" hasGutter>
42	                    <StackItem>
43	                      <TemplateInfoSection />
44	                      {hardwareDevicesCount !== 0 && (
45	                        <ExpandableSection
46	                          toggleText={t('Hardware devices ({{devices}})', {
47	                            devices: hardwareDevicesCount,
48	                          })}
49	                          isIndented
50	                        >
51	                          <DescriptionListDescription>
52	                            <HardwareDevices hideEdit vm={vm} />
53	                          </DescriptionListDescription>
54	                        </ExpandableSection>
55	                      )}
56	                    </StackItem>
57	                  </Stack>
58	                </GridItem>
59	
60	                <GridItem span={6}>
61	                  <StorageSection />
62	
63	                  <FieldsSections />
64	                </GridItem>
65	              </Grid>
66	            </Form>
67	          </FormProvider>
68	        </div>
69	      </div>
70	    </div>
71	  );
72	});
73	TemplatesCatalogDrawerPanel.displayName = 'TemplatesCatalogDrawerPanel';

